; 魔女の隠れ家

name = 魔女の隠れ家Ｂ７
insideName = Ｂ７
upper = 魔女の隠れ家Ｂ６
pool = 魔女の隠れ家Ｂ７水中
level = 23
bgm = hideout
external = s:1
roof = stone
shadow = dark
sky = black
blank = rock
outfield = marble
antiWarp = true

; 各パーツ
━ = stoney
　 = marble
～ = pool
❑ = cube
／ = door
⧻ = fence
☖ = gate
︻ = panel
㊤ = ladderu
㊦ = ladderd
⑹ = br_maxmp
⑺ = br_maxmp

; 宝箱
box[1] = 精霊の縫い糸,精霊の縫い糸,ドルフィンスーツ_u
box[2] = 罠はない,炎のロッド,魔法の鎖かたびら,魔女のスカート,貝のお守り,解呪の巻物・改,男の秘薬,女の秘薬

